export function shuffleArray<T>({ array }: { array: T[] }): T[] {
	const shuffled = [...array];
	for (let i = shuffled.length - 1; i > 0; i--) {
		const j = Math.floor(Math.random() * (i + 1));
		[shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]] as [T, T];
	}
	return shuffled;
}

export function injectItemsRandomlyInFirstN<T>({
	items,
	targetArray,
	firstN,
}: {
	items: T[];
	targetArray: T[];
	firstN: number;
}): T[] {
	if (items.length === 0) {
		return [...targetArray];
	}

	const result = [...targetArray];
	const numberOfItemsToInject = items.length;
	const maxPosition = Math.max(firstN, numberOfItemsToInject);
	const availablePositions = Array.from({ length: maxPosition }, (_, i) => i);
	const shuffledPositions = shuffleArray({ array: availablePositions });
	const selectedPositions = shuffledPositions
		.slice(0, numberOfItemsToInject)
		.sort((a, b) => a - b);

	for (let i = 0; i < numberOfItemsToInject; i++) {
		const position = selectedPositions[i];
		const item = items[i];
		if (position !== undefined && item !== undefined) {
			result.splice(position, 0, item);
		}
	}

	return result;
}

